import React, { useState } from 'react';
import "./index.css";
import { Form, Button } from 'antd';
import Api from '../../helpers/api';
import { message } from "antd";

import {
    ArrowLeftOutlined
} from '@ant-design/icons';

const api = new Api();

const Forgot = (props) => {

    const [form] = Form.useForm();
    const [errors, setErrors] = useState({})
    const [isLoading, setIsLoading] = useState(false)
    const [formData, setFormData] = useState({ email: "" })

    const handleInput = (e, name) => {
        setFormData({ ...formData, [name]: e.target.value })
    }

    const onFinish = () => {
        setIsLoading(true)
        api.resetPassword(formData)
            .then(response => {
                const { data } = response
                setIsLoading(false)
                props.history.push('/login')
                message.success(data.message);
            })
            .catch(error => {
                setIsLoading(false)
                if (error.response && error.response.data) {
                    const { errors } = error.response.data
                    setErrors(errors)
                    message.error(error.response.data.message);
                }
            });
    };

    return (
        <div className="d-lg-flex half">
            <div className="bg order-1 order-md-2 login-form-wrapper" />
            <div className="contents order-2 order-md-1">
                <div className="container" style={{ backgroundColor: '#fff' }}>
                    <div className="row align-items-center justify-content-center">
                        <div className="col-md-7">
                            <h3>Forgot Password</h3>
                            <p className="mb-4">Input your email below to get password reset link</p>

                            <Form form={form} onFinish={onFinish}>
                                <div className="form-group first last">
                                    <label>Email  <span style={{ color: 'red' }}>{errors && errors.email ? errors.email : null}</span></label>
                                    <input
                                        onChange={value => handleInput(value, 'email')}
                                        type="text"
                                        className="form-control"
                                        placeholder="your-email@mail.com" />
                                </div>

                                <Button className="form-button"
                                    size="large"
                                    block
                                    type="primary"
                                    htmlType="submit"
                                    loading={isLoading}>
                                    Resset Password
                                </Button>

                                <Button
                                    onClick={() => { props.history.push('/login') }}
                                    className="form-button"
                                    icon={<ArrowLeftOutlined />}
                                    size="large" block>Back to Login</Button>
                            </Form>

                        </div>
                    </div>
                </div>
            </div>
        </div>
    )
}

export default Forgot;
